<section class="card detail-header"><div><h2><?= e($transaction['plot_number'] ?? 'Transaction') ?></h2><p><?= e($transaction['transaction_type'] ?? '') ?> to <?= e($transaction['to_owner'] ?? '') ?></p></div><span class="badge <?= e($transaction['status'] ?? '') ?>"><?= e($transaction['status'] ?? '') ?></span></section><section class="card"><dl class="detail-list"><dt>Amount</dt>    <dd><?= $transaction['amount'] !== null ? e($transaction['currency'] ?? 'NGN') . ' ' . number_format((float) $transaction['amount'], 2) : '—' ?></dd><dt>Date</dt><dd><?= e($transaction['transaction_date'] ?? '') ?></dd><dt>Notes</dt><dd><?= e($transaction['notes'] ?? '') ?></dd></dl><?php if (($transaction['status'] ?? '') === 'pending' && in_array($_SESSION['role'] ?? '', ['superadmin','admin'], true)): ?><div class="toolbar"><form method="post" action="/transactions/<?= e($transaction['id']) ?>/approve"><?= csrf_field() ?><button class="btn primary">Approve</button></form><form method="post" action="/transactions/<?= e($transaction['id']) ?>/reject"><?= csrf_field() ?><button class="btn danger">Reject</button></form></div><?php endif; ?></section>
